extern int pid_heater_control(float sp,float pv,float dt,float kp,float ki,float kd,float* intg,float* lastE);
extern float epoxy_degree_of_cure(float log_iv,float log_iv_min,float log_iv_max);

const float SP=80.0f,KP=3.0f,KI=0.2f,KD=0.8f,TEMP_MAX=90.0f;
const int PELTIER_PIN=9,DEA_PIN=A0,NTC_PIN=A1;
const float R_REF=10000.0f,B_NTC=3950.0f,T0_NTC=298.15f;
const float IV_MIN=3.5f,IV_MAX=9.5f;
float intg=0,lastE=0;

// === NTC Thermistor ===
void therm_init(){pinMode(NTC_PIN,INPUT);}
float therm_read(){
  float v=analogRead(NTC_PIN)*3.3f/1023.0f;
  float r=R_REF*v/(3.3f-v);
  float inv_T=1.0f/T0_NTC+(1.0f/B_NTC)*log(r/R_REF);
  return 1.0f/inv_T-273.15f;
}

// === DEA Sensor ===
void dea_init(){pinMode(DEA_PIN,INPUT);}
float dea_log_iv(){float v=analogRead(DEA_PIN)/1023.0f;return IV_MIN+v*(IV_MAX-IV_MIN);}

// === Peltier Stage ===
void peltier_init(){pinMode(PELTIER_PIN,OUTPUT);analogWrite(PELTIER_PIN,0);}
void peltier_set(int p){analogWrite(PELTIER_PIN,constrain(p,0,255));}

// === Fault Handler ===
bool fault_check(float t){if(t>TEMP_MAX){peltier_set(0);Serial.println("FAULT:OVERTEMP");return true;}return false;}

// === Serial Logger ===
void logger_header(){Serial.println("t_s,temp_C,alpha,pwm,event");}
void logger_write(float t_s,float temp,float alpha,int pwm,const char* ev){
  Serial.print(t_s,1);Serial.print(',');Serial.print(temp,2);Serial.print(',');Serial.print(alpha,4);Serial.print(',');Serial.print(pwm);Serial.print(',');Serial.println(ev);}

void setup(){
  Serial.begin(115200);
  therm_init();dea_init();peltier_init();
  logger_header();
}

unsigned long lastMs=0;
void loop(){
  unsigned long now=millis();
  float dt=(now-lastMs)/1000.0f;
  if(dt<2.0f)return;
  lastMs=now;
  float temp=therm_read();
  float logIV=dea_log_iv();
  float alpha=epoxy_degree_of_cure(logIV,IV_MIN,IV_MAX);
  if(fault_check(temp))return;
  const char* ev="";
  if(alpha>=0.95f){peltier_set(0);ev="CURE_COMPLETE";logger_write(now/1000.0f,temp,alpha,0,ev);return;}
  if(alpha>=0.85f)ev="VITRIFY";
  else if(alpha>=0.55f)ev="GEL";
  int pwm=pid_heater_control(SP,temp,dt,KP,KI,KD,&intg,&lastE);
  peltier_set(pwm);
  logger_write(now/1000.0f,temp,alpha,pwm,ev);
}
